"use client";

import { useEffect, useMemo, useState } from "react";

type VerifyOk =
  | { ok: true; status: "verified"; record: any }
  | { ok: true; status: "not_found" };

type VerifyErr =
  | { ok: false; error: "missing_code" }
  | { ok: false; error: "missing_env" }
  | { ok: false; error: "db_error"; details?: string }
  | { ok: false; error: string; details?: string };

type VerifyResponse = VerifyOk | VerifyErr;

export default function VerifyPage() {
  const [loading, setLoading] = useState(true);
  const [res, setRes] = useState<VerifyResponse | null>(null);

  const code = useMemo(() => {
    if (typeof window === "undefined") return "";
    const sp = new URLSearchParams(window.location.search);
    return (sp.get("code") ?? "").trim();
  }, []);

  useEffect(() => {
    let cancelled = false;

    async function run() {
      try {
        if (!code) {
          setRes({ ok: false, error: "missing_code" });
          setLoading(false);
          return;
        }

        setLoading(true);
        const r = await fetch(`/api/verify?code=${encodeURIComponent(code)}`, {
          cache: "no-store",
        });
        const j = (await r.json()) as VerifyResponse;
        if (!cancelled) setRes(j);
      } catch (e: any) {
        if (!cancelled) setRes({ ok: false, error: "network_error", details: e?.message });
      } finally {
        if (!cancelled) setLoading(false);
      }
    }

    run();
    return () => {
      cancelled = true;
    };
  }, [code]);

  const record = (res && "ok" in res && res.ok && res.status === "verified") ? res.record : null;

  const name =
    record?.full_name ||
    record?.name ||
    record?.holder_name ||
    record?.student_name ||
    "—";

  const course =
    record?.course_name ||
    record?.course ||
    record?.program ||
    record?.title ||
    "—";

  const license =
    record?.license_code ||
    record?.code ||
    record?.license ||
    code ||
    "—";

  return (
    <main style={styles.page}>
      <div style={styles.bgGlow} />

      <div style={styles.container}>
        <header style={styles.header}>
          <div style={styles.brand}>
            <div style={styles.logoMark}>A</div>
            <div>
              <div style={styles.brandName}>ALBATROS SAILING</div>
              <div style={styles.brandSub}>Training Verification</div>
            </div>
          </div>

          <div style={styles.badgeWrap}>
            {loading ? (
              <span style={{ ...styles.badge, ...styles.badgeNeutral }}>Checking…</span>
            ) : res?.ok === true && (res as any).status === "verified" ? (
              <span style={{ ...styles.badge, ...styles.badgeOk }}>Verified</span>
            ) : (
              <span style={{ ...styles.badge, ...styles.badgeFail }}>Not Verified</span>
            )}
          </div>
        </header>

        <section style={styles.card}>
          <div style={styles.cardTop}>
            <div>
              <h1 style={styles.h1}>Lisans Doğrulama</h1>
              <p style={styles.pMuted}>
                Bu sayfa Albatros Sailing eğitim kayıtlarını doğrulamak için kullanılır.
              </p>
            </div>

            <div style={styles.codeBox}>
              <div style={styles.codeLabel}>Sorgu Kodu</div>
              <div style={styles.codeValue}>{code || "—"}</div>
            </div>
          </div>

          <div style={styles.hr} />

          {loading ? (
            <div style={styles.loading}>
              <div style={styles.skeleton} />
              <div style={styles.skeleton} />
              <div style={styles.skeletonSmall} />
            </div>
          ) : !res ? (
            <p style={styles.p}>Sonuç yok.</p>
          ) : res.ok === false ? (
            <div style={styles.resultFail}>
              <div style={styles.resultTitle}>Bir hata oluştu</div>
              <div style={styles.resultText}>
                <b>Hata:</b> {res.error}
                {("details" in res && res.details) ? <div style={{ marginTop: 6 }}>{res.details}</div> : null}
              </div>
            </div>
          ) : (res as any).status === "not_found" ? (
            <div style={styles.resultFail}>
              <div style={styles.resultTitle}>Kayıt bulunamadı</div>
              <div style={styles.resultText}>
                Bu kod ile eşleşen aktif bir kayıt bulunamadı.
              </div>
            </div>
          ) : (
            <div style={styles.resultOk}>
              <div style={styles.grid}>
                <Info label="İsim" value={name} />
                <Info label="Kurs" value={course} />
                <Info label="Lisans Kodu" value={license} />
                <Info label="Lokasyon" value={record?.location || "—"} />
                <Info label="Tarih" value={record?.issue_date || record?.created_at || "—"} />
                <Info label="Durum" value={record?.status || "active"} />
              </div>

              <div style={styles.note}>
                <b>Not:</b> Bu doğrulama ekranı resmi devlet lisansı değildir. Geçerlilik yalnızca Albatros Sailing
                eğitim tamamlama kayıtları içindir.
              </div>
            </div>
          )}
        </section>

        <footer style={styles.footer}>
          <span style={styles.footerText}>© {new Date().getFullYear()} Albatros Sailing</span>
          <span style={styles.footerText}>/verify • v1</span>
        </footer>
      </div>
    </main>
  );
}

function Info({ label, value }: { label: string; value: string }) {
  return (
    <div style={styles.info}>
      <div style={styles.infoLabel}>{label}</div>
      <div style={styles.infoValue}>{value}</div>
    </div>
  );
}

